class Solution:
    def minFlips(self, a, b, c):
        flips = 0
        while a or b or c:
            ba, bb, bc = a & 1, b & 1, c & 1
            if bc == 0:
                flips += ba + bb
            elif ba == 0 and bb == 0:
                flips += 1
            a >>= 1; b >>= 1; c >>= 1
        return flips

