var minFlips = function(a, b, c) {
    let flips = 0;
    while (a || b || c) {
        const ba = a & 1, bb = b & 1, bc = c & 1;
        if (bc === 0) flips += ba + bb;
        else if (ba === 0 && bb === 0) flips += 1;
        a >>= 1; b >>= 1; c >>= 1;
    }
    return flips;
};
